={
  "content": "<@YOUR_DISCORD_USER_ID>",
  "embeds": [
    {
      "title": "🔥 FIRING — {{ ($json.body.alerts || [{}])[0].labels?.alertname || 'Grafana Alert' }}",
      "description": "{{ ($json.body.alerts || [{}])[0].annotations?.summary || 'Alert condition is true' }}",
      "color": 15158332,
      "fields": [
        {
          "name": "Why Fired",
          "value": "{{ ($json.body.alerts || [{}])[0].annotations?.trigger_logic || (($json.body.alerts || [{}])[0].annotations?.description || 'Threshold condition evaluated true.') }}",
          "inline": false
        },
        {
          "name": "Trigger Query / Threshold / Window",
          "value": "Query: `{{ ($json.body.alerts || [{}])[0].annotations?.trigger_query || (($json.body.alerts || [{}])[0].labels?.detection_query || 'N/A') }}`\nThreshold: `{{ ($json.body.alerts || [{}])[0].annotations?.trigger_threshold || (($json.body.alerts || [{}])[0].labels?.threshold || 'N/A') }}`\nWindow: `{{ ($json.body.alerts || [{}])[0].annotations?.trigger_window || (($json.body.alerts || [{}])[0].labels?.window || 'N/A') }}`",
          "inline": false
        },
        {
          "name": "Observed Value(s)",
          "value": "{{ (($json.body.alerts || [{}])[0].valueString || JSON.stringify(($json.body.alerts || [{}])[0].values || {})).slice(0, 900) || 'N/A' }}",
          "inline": false
        },
        {
          "name": "Affected Device / Host",
          "value": "{{ ($json.body.alerts || [{}])[0].labels?.agent || ($json.body.alerts || [{}])[0].labels?.agent_name || ($json.body.alerts || [{}])[0].labels?.instance || ($json.body.alerts || [{}])[0].labels?.host || ($json.body.alerts || [{}])[0].labels?.device || 'N/A') }}",
          "inline": true
        },
        {
          "name": "Source / User / File",
          "value": "srcip=`{{ ($json.body.alerts || [{}])[0].labels?.srcip || 'N/A' }}`\nuser=`{{ ($json.body.alerts || [{}])[0].labels?.user || ($json.body.alerts || [{}])[0].labels?.username || 'N/A' }}`\npath=`{{ ($json.body.alerts || [{}])[0].labels?.path || ($json.body.alerts || [{}])[0].labels?.file || 'N/A' }}`",
          "inline": true
        },
        {
          "name": "Severity / Source / Group",
          "value": "sev=`{{ ($json.body.alerts || [{}])[0].labels?.severity || 'unknown' }}` src=`{{ ($json.body.alerts || [{}])[0].labels?.source || 'unknown' }}` group=`{{ ($json.body.alerts || [{}])[0].labels?.alert_group || 'N/A' }}`",
          "inline": false
        },
        {
          "name": "Starts At",
          "value": "{{ ($json.body.alerts || [{}])[0].startsAt || 'N/A' }}",
          "inline": true
        },
        {
          "name": "Dashboard / Panel",
          "value": "{{ ($json.body.alerts || [{}])[0].dashboardURL || 'N/A' }}\n{{ ($json.body.alerts || [{}])[0].panelURL || '' }}",
          "inline": false
        },
        {
          "name": "Details",
          "value": "{{ (($json.body.alerts || [{}])[0].annotations?.description || 'N/A').slice(0, 900) }}",
          "inline": false
        }
      ],
      "timestamp": "{{ ($json.body.alerts || [{}])[0].startsAt || new Date().toISOString() }}"
    }
  ]
}

={
  "embeds": [
    {
      "title": "✅ RESOLVED — {{ ($json.body.alerts || [{}])[0].labels?.alertname || 'Grafana Alert' }}",
      "description": "{{ ($json.body.alerts || [{}])[0].annotations?.summary || 'Alert condition cleared' }}",
      "color": 3066993,
      "fields": [
        {
          "name": "Why Resolved",
          "value": "{{ ($json.body.alerts || [{}])[0].annotations?.resolve_logic || 'Condition is no longer true in the current evaluation window (value <= threshold or prior events aged out).' }}",
          "inline": false
        },
        {
          "name": "Trigger Query / Threshold / Window",
          "value": "Query: `{{ ($json.body.alerts || [{}])[0].annotations?.trigger_query || (($json.body.alerts || [{}])[0].labels?.detection_query || 'N/A') }}`\nThreshold: `{{ ($json.body.alerts || [{}])[0].annotations?.trigger_threshold || (($json.body.alerts || [{}])[0].labels?.threshold || 'N/A') }}`\nWindow: `{{ ($json.body.alerts || [{}])[0].annotations?.trigger_window || (($json.body.alerts || [{}])[0].labels?.window || 'N/A') }}`",
          "inline": false
        },
        {
          "name": "Current Value(s)",
          "value": "{{ (($json.body.alerts || [{}])[0].valueString || JSON.stringify(($json.body.alerts || [{}])[0].values || {})).slice(0, 900) || 'N/A' }}",
          "inline": false
        },
        {
          "name": "Affected Device / Host",
          "value": "{{ ($json.body.alerts || [{}])[0].labels?.agent || ($json.body.alerts || [{}])[0].labels?.agent_name || ($json.body.alerts || [{}])[0].labels?.instance || ($json.body.alerts || [{}])[0].labels?.host || ($json.body.alerts || [{}])[0].labels?.device || 'N/A') }}",
          "inline": true
        },
        {
          "name": "Incident Duration",
          "value": "{{ (() => { const a = ($json.body.alerts || [{}])[0]; if (!a?.startsAt || !a?.endsAt) return 'N/A'; const ms = new Date(a.endsAt).getTime() - new Date(a.startsAt).getTime(); if (!Number.isFinite(ms) || ms < 0) return 'N/A'; const mins = Math.round(ms / 60000); return mins + ' minute(s)'; })() }}",
          "inline": true
        },
        {
          "name": "Resolved At",
          "value": "{{ ($json.body.alerts || [{}])[0].endsAt || 'N/A' }}",
          "inline": true
        },
        {
          "name": "Details",
          "value": "{{ (($json.body.alerts || [{}])[0].annotations?.description || 'N/A').slice(0, 900) }}",
          "inline": false
        }
      ],
      "timestamp": "{{ ($json.body.alerts || [{}])[0].endsAt || new Date().toISOString() }}"
    }
  ]
}
